/**
 * @summary List activity feed (role-filtered, last 20 missed events)
 */
export const getListActivityUrl = (params?: ListActivityParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/activity?${stringifiedParams}`
    : `/api/activity`;
};

export const listActivity = async (
  params?: ListActivityParams,
  options?: RequestInit,
): Promise<ActivityEvent[]> => {
  return customFetch<ActivityEvent[]>(getListActivityUrl(params), {
    ...options,
    method: "GET",
  });
};

